type HorseMarkProps = {
  badgeFill?: string;
  markFill?: string;
  size?: number;
  radius?: number;
  className?: string;
};

export function HorseMark({
  badgeFill = "#fcdf68",
  markFill = "#1d334e",
  size = 100,
  radius = 10,
  className,
}: HorseMarkProps) {
  return (
    <svg
      viewBox="0 0 128 106"
      width={size}
      height={(size * 106) / 128}
      aria-hidden="true"
      className={className}
    >
      <rect width="128" height="106" rx={radius} ry={radius} fill={badgeFill} />
      <g
        transform="matrix(0.8749897862672958,0,0,0.8749897862672958,20.001024189557,9.35420721006751)"
        fill={markFill}
      >
        <path fillRule="evenodd" clipRule="evenodd" d={HORSE_PATH} />
      </g>
    </svg>
  );
}

type HorseSilhouetteProps = {
  size?: number;
  className?: string;
};

// Just the horse silhouette, badge stripped, inherits `currentColor`.
// For icon contexts (nav buttons, list rows) where the brand mark needs to
// theme alongside surrounding text.
export function HorseSilhouette({ size = 22, className }: HorseSilhouetteProps) {
  return (
    <svg
      viewBox="-3 17 106 70"
      width={size}
      height={size}
      fill="currentColor"
      aria-hidden="true"
      className={className}
    >
      <path fillRule="evenodd" clipRule="evenodd" d={HORSE_PATH} />
    </svg>
  );
}

type WordmarkProps = {
  color?: string;
  height?: number;
  className?: string;
};

export function Wordmark({ color = "#fcdf68", height = 64, className }: WordmarkProps) {
  const W = 269;
  const H = 78;
  return (
    <svg
      viewBox={`0 0 ${W} ${H}`}
      height={height}
      width={(height * W) / H}
      aria-hidden="true"
      className={className}
    >
      <g transform="matrix(4.893736073581272,0,0,4.893736073581272,0,2)" fill={color}>
        <path d={WORDMARK_PATH} />
      </g>
    </svg>
  );
}

type FullLogoProps = {
  badgeFill?: string;
  markFill?: string;
  wordmarkFill?: string;
  height?: number;
  gap?: number;
  className?: string;
  title?: string;
};

export function FullLogo({
  badgeFill = "#fcdf68",
  markFill = "#1d334e",
  wordmarkFill = "#fcdf68",
  height = 100,
  gap = 14,
  className,
  title = "mal.kr",
}: FullLogoProps) {
  const badgeW = 128;
  const wordOffset = 141.34;
  const totalW = 410.5;
  const scale = height / 106;
  return (
    <svg
      viewBox={`0 0 ${totalW} 106`}
      width={totalW * scale}
      height={106 * scale}
      preserveAspectRatio="xMidYMid meet"
      role="img"
      aria-label={title}
      className={className}
    >
      <rect width={badgeW} height="106" rx="10" ry="10" fill={badgeFill} />
      <g
        transform="matrix(0.8749897862672958,0,0,0.8749897862672958,20.001024189557,9.35420721006751)"
        fill={markFill}
      >
        <path fillRule="evenodd" clipRule="evenodd" d={HORSE_PATH} />
      </g>
      <g
        transform={`matrix(4.893736073581272,0,0,4.893736073581272,${wordOffset + gap - 14},-7.881432599120256)`}
        fill={wordmarkFill}
      >
        <path d={WORDMARK_PATH} />
      </g>
    </svg>
  );
}
